        fclose(file);
        free(contents);
        return;
    }

    // Decrypt the file contents
    AES_KEY aes_key;
    AES_set_decrypt_key((const unsigned char *)key, 256, &aes_key);
    AES_decrypt(contents, contents, &aes_key);

    // Write the decrypted contents back to the file
    if (fwrite(contents, 1, 1024, file) != 1024) {
        printf("Error writing file\n");
        fclose(file);
        free(contents);
        return;
    }

    // Close the file
    fclose(file);
    free(contents);
}

